const PROCESSING_FEE = 5;                                          // 1 const + 1 assignment = 7

interface Item { ... }                                              // structural, not counted

const BASE_PREMIUMS: Record<string, number> = {                    // 6 const + 1 assignment = 13
  sword: 100, amulet: 60, staff: 80, potion: 40, rune: 25, moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);            // 2 const + 1 invocation + 1 assignment = 10

const BLOCK_SIZE = 3;                                               // 1 const + 1 assignment = 7
const BLOCK_PREMIUM = 60;                                           // 1 const + 1 assignment = 7

const basePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
