};
// total itemPremium: 40

const componentBlockPremium = (type: string, count: number): number =>
  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);
// 2 bindings(type, count) + 1 conditional(?) + 1 invocation(===) + 1 invocation(*) + 1 invocation(index) + 1 conditional(??) + 1 const(0) = 16

