59	const DEDUCTIBLE = 100;
60	
61	export const claim = (
62	  policy: { items: Item[] },
63	  damages: { itemType: string; amount: number }[]
64	): { payout: number; remainingCap: number } => {
65	  const payout = damages.reduce((sum, d) => sum + Math.max(0, d.amount - DEDUCTIBLE), 0);
66	  return { payout, remainingCap: 0 };
67	};
