69	export const quote = (
70	  customer: { yearsWithMHPCO: number },
71	  items: Item[],
72	  isFollowUp: boolean
73	): number => {
74	  const premium = itemsPremium(items);
75	  const policyBasePremium = items.reduce((sum, item) => sum + basePremium(item), 0);
76	  const firstInsurance = policyBasePremium * 0.1;
77	  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? policyBasePremium * 0.2 : 0;
78	  const followUpDiscount = isFollowUp ? policyBasePremium * 0.15 : 0;
79	  return Math.ceil(premium + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
80	};
